import com.example.profileupload.exception.InvalidImageFileException;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.util.StringUtils;
import org.springframework.web.multipart.MultipartFile;

import java.io.IOException;
import java.io.InputStream;
import java.nio.file.*;
import java.util.Locale;
import java.util.Set;
import java.util.UUID;

@Service
public class FileStorageService {

    private static final Set<String> ALLOWED_EXTENSIONS = Set.of("jpg", "jpeg", "png", "gif", "webp", "bmp");
    private static final Set<String> ALLOWED_CONTENT_TYPES = Set.of(
            "image/jpeg",
            "image/png",
            "image/gif",
            "image/webp",
            "image/bmp"
    );

    private final Path uploadRoot;
    private final String baseUrl;

    public FileStorageService(@Value("${app.upload.dir:uploads}") String uploadDir,
                              @Value("${app.upload.base-url:http://localhost:8080}") String baseUrl) {
        this.uploadRoot = Paths.get(uploadDir).toAbsolutePath().normalize();
        this.baseUrl = baseUrl.endsWith("/") ? baseUrl.substring(0, baseUrl.length() - 1) : baseUrl;
        try {
            Files.createDirectories(this.uploadRoot);
        } catch (IOException e) {
            throw new IllegalStateException("Could not create upload directory", e);
        }
    }

    public String storeProfilePicture(String userId, MultipartFile file) {
        validate(file);

        String originalFilename = StringUtils.cleanPath(file.getOriginalFilename() == null ? "" : file.getOriginalFilename());
        String extension = getExtension(originalFilename, file.getContentType());
        String safeUserId = userId.replaceAll("[^a-zA-Z0-9._-]", "_");
        String fileName = safeUserId + "-" + UUID.randomUUID() + "." + extension;

        Path userDir = uploadRoot.resolve("profiles").resolve(safeUserId).normalize();
        try {
            Files.createDirectories(userDir);
            Path target = userDir.resolve(fileName).normalize();
            if (!target.startsWith(uploadRoot)) {
                throw new InvalidImageFileException("Invalid file path");
            }
            try (InputStream in = file.getInputStream()) {
                Files.copy(in, target, StandardCopyOption.REPLACE_EXISTING);
            }
            return baseUrl + "/uploads/profiles/" + safeUserId + "/" + fileName;
        } catch (IOException e) {
            throw new IllegalStateException("Failed to store file", e);
        }
    }

    private void validate(MultipartFile file) {
        if (file == null || file.isEmpty()) {
            throw new InvalidImageFileException("File is required");
        }
        String contentType = file.getContentType();
        if (contentType == null || !ALLOWED_CONTENT_TYPES.contains(contentType.toLowerCase(Locale.ROOT))) {
            throw new InvalidImageFileException("Only common image formats are allowed");
        }
        String originalFilename = file.getOriginalFilename();
        String extension = getExtension(originalFilename == null ? "" : originalFilename, contentType);
        if (!ALLOWED_EXTENSIONS.contains(extension)) {
            throw new InvalidImageFileException("Only common image formats are allowed");
        }
    }

    private String getExtension(String filename, String contentType) {
        String ext = "";
        int idx = filename.lastIndexOf('.');
        if (idx >= 0 && idx < filename.length() - 1) {
            ext = filename.substring(idx + 1).toLowerCase(Locale.ROOT);
        } else if (contentType != null) {
            ext = switch (contentType.toLowerCase(Locale.ROOT)) {
                case "image/jpeg" -> "jpg";
                case "image/png" -> "png";
                case "image/gif" -> "gif";
                case "image/webp" -> "webp";
                case "image/bmp" -> "bmp";
                default -> "";
            };
        }
        if ("jpeg".equals(ext)) {
            return "jpg";
        }
        return ext;
    }
}

